sys_ui_action.script:
// Wrap the script in a function to allow the use of return statements
runServerCode();

function runServerCode() {
    // 1. Validate that a maintenance issue comment is present
    if (!current.close_notes || current.close_notes.nil()) {
        gs.addErrorMessage('A comment is required in the Maintenance issue field before flagging for maintenance.');
        current.setAbortAction(true); // Stop ServiceNow processing further
        action.setRedirectURL(current); // Keep user on the current page
        return; 
    }

    // 2. Create the Workspace Maintenance record
    var maint = new GlideRecord('x_1534869_wrm_workspace_maintenance');
    maint.initialize();
    maint.reservation = current.getUniqueValue()
    maint.workspace = current.workspace;
    maint.workspace_status = 'in_maintenance';
    maint.ticket_status = 'open';
    maint.date_reported = new GlideDateTime(); 
    maint.issue_description = current.close_notes;

    // 3. Assign to Workspace Maintenance Team
    var grp = new GlideRecord('sys_user_group');
    grp.addQuery('name', 'Workspace Maintenance Team');
    grp.query();
    if (grp.next()) {
        maint.assignment_group = grp.getUniqueValue(); 
    }

    // 4. Insert record and refresh current page
    maint.insert();
    current.update(); 
    action.setRedirectURL(current); 
    gs.addInfoMessage('Maintenance ticket created successfully.');
}
